/**
 * @fileoverview Shared layout constants — spacing, margins, gaps.
 *
 * Centralizes common layout values that appear across multiple components.
 *
 * @module shared/tokens/layout
 */

/**
 * Default gap (px) between a trigger and its floating dropdown.
 * Used by: ClipBox, DynamicSearch, Combobox, DatePicker.
 */
export const DROPDOWN_GAP_PX = 4;

/**
 * Viewport edge margin (px) — minimum distance from the viewport edge
 * when positioning floating elements.
 */
export const VIEWPORT_MARGIN_PX = 8;
